    let runCount = 0;

    $effect(() => {
      console.log('Effect run:', stateValue, derivedValue);
      runCount++;

      return () => {
        teardownValue = derivedValue;
        console.log('Teardown - derivedValue:', teardownValue);
      };
    });

    // Trigger a change
    stateValue = 2;

    // At this point, the teardown should have been called with the previous value (2)
    // But according to the bug, it gets the latest value (4)

    if (teardownValue !== 2) {
      testResults.failed++;
      testResults.details.push(`Test 1 FAILED: Expected teardownValue to be 2 (previous value), got ${teardownValue}`);
    } else {
      testResults.passed++;
      testResults.details.push('Test 1 PASSED: Derived value in teardown is correct');
    }

  } catch (error) {
    testResults.failed++;
    testResults.details.push(`Test 1 ERROR: ${error.message}`);
    console.error('Test 1 error:', error);
  }

  // Test 2: More complex scenario with nested derived values
  try {
    const { useContext, createContext } = require('./packages/svelte/src/index-client.js');

    let stateValue = $state(10);
    let derived1 = $derived(() => stateValue + 5);
    let derived2 = $derived(() => derived1 * 2);

    let teardownValues = [];

    $effect(() => {
      console.log('Effect run - derived2:', derived2);

      return () => {
        teardownValues.push({
          derived1: derived1,
          derived2: derived2
        });
        console.log('Teardown - derived1:', derived1, 'derived2:', derived2);
      };
    });

    // Trigger first change
    stateValue = 20;

    // Teardown should be called with previous values
    if (teardownValues.length > 0) {
      const lastTeardown = teardownValues[teardownValues.length - 1];
      if (lastTeardown.derived1 !== 15 || lastTeardown.derived2 !== 30) {
        testResults.failed++;
        testResults.details.push(`Test 2 FAILED: Expected previous values (15, 30), got (${lastTeardown.derived1}, ${lastTeardown.derived2})`);
      } else {
        testResults.passed++;
        testResults.details.push('Test 2 PASSED: Nested derived values in teardown are correct');
      }
    } else {
      testResults.failed++;
      testResults.details.push('Test 2 FAILED: No teardown was called');
    }

